import{_ as t,o as a,c as d,ag as i}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"Admin","description":"","frontmatter":{"uid":"5d79cdf1-075f-4fb9-8261-bb9aa725e047 ... ..."},"headers":[],"relativePath":"10_core/40_service_apps/120_applications/admin.md","filePath":"10_core/40_service_apps/120_applications/admin.md"}'),o={name:"10_core/40_service_apps/120_applications/admin.md"};function r(s,e,n,c,l,m){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h1><blockquote><p>Quarantine notice: this page still reflects the older tenant and client-platform admin model. It is retained for salvage, not as active QiAccess Start doctrine. See <code>08_appendices/20_legacy/qiaccess_start_legacy_quarantine.md</code>.</p></blockquote><p>The Admin surface is the internal operational dashboard for system operators and developers.</p><h2 id="admin-vs-portal" tabindex="-1">Admin vs Portal <a class="header-anchor" href="#admin-vs-portal" aria-label="Permalink to &quot;Admin vs Portal&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Admin</th><th>Portal</th></tr></thead><tbody><tr><td>Operator / developer only</td><td>Client-facing</td></tr><tr><td>All tenants visible</td><td>Single tenant context</td></tr><tr><td>Low-level system controls</td><td>Business workflow</td></tr><tr><td>Pipeline monitoring</td><td>Domain data</td></tr></tbody></table><h2 id="admin-capabilities" tabindex="-1">Admin Capabilities <a class="header-anchor" href="#admin-capabilities" aria-label="Permalink to &quot;Admin Capabilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Source</th></tr></thead><tbody><tr><td>Tenant management</td><td><code>qione.tenants</code></td></tr><tr><td>User and role management</td><td><code>qione.tenant_members</code>, <code>qione.member_roles</code></td></tr><tr><td>Module assignment</td><td><code>qione.tenant_modules</code></td></tr><tr><td>Job queue monitoring</td><td><code>qisys.jobs</code></td></tr><tr><td>System events log</td><td><code>qisys.system_events</code></td></tr><tr><td>Worker status</td><td><code>qisys.worker_status</code></td></tr><tr><td>Archive inspection</td><td><code>qiarchive.archive_files</code></td></tr><tr><td>Pipeline failure review</td><td><code>qiarchive.ingest_jobs</code></td></tr><tr><td>Device enrollment</td><td><code>qisys.devices</code></td></tr><tr><td>Device registry</td><td><code>qisys.devices</code>, <code>qisys.device_capabilities</code></td></tr><tr><td>Node health / heartbeat monitoring</td><td><code>qisys.device_heartbeats</code></td></tr><tr><td>Assigned watch folder management</td><td><code>qisys.device_watch_assignments</code></td></tr><tr><td>Drop zone policy</td><td><code>qisys.device_watch_assignments</code></td></tr><tr><td>Runtime version/config drift</td><td><code>qisys.device_agents</code></td></tr><tr><td>Job dispatch / retry by node</td><td><code>qisys.device_jobs</code></td></tr><tr><td>Audit trail for fleet actions</td><td><code>qisys.device_events</code></td></tr></tbody></table><h2 id="nocodb-as-admin-surface" tabindex="-1">NocoDB as Admin Surface <a class="header-anchor" href="#nocodb-as-admin-surface" aria-label="Permalink to &quot;NocoDB as Admin Surface&quot;">​</a></h2><p>NocoDB provides a human-friendly admin interface over Supabase Postgres without requiring custom admin app code. It is appropriate for internal operational use but must:</p><ul><li>Never be exposed publicly</li><li>Always use service role access carefully</li><li>Never be used to bypass RLS for tenant data</li></ul><h2 id="admin-law" tabindex="-1">Admin Law <a class="header-anchor" href="#admin-law" aria-label="Permalink to &quot;Admin Law&quot;">​</a></h2><ul><li>Admin surfaces must authenticate with elevated roles — never anon keys</li><li>Devices authenticate with enrollment/agent credentials</li><li>Admin surfaces must not expose tenant data across tenant boundaries</li><li>All node-orchestration actions must write audit events in <code>qisys.device_events</code> or <code>qisys.system_events</code></li><li>Admin must never bypass the explicit <code>QiArchive</code> registration contract</li></ul>',12)])])}const u=t(o,[["render",r]]);export{h as __pageData,u as default};
